 1	import * as React from 'react';
 2	import { PageSection, TextInputTypes } from '@patternfly/react-core';
 3	import MultiColumnField from '../pipelines-details/multi-column-field/MultiColumnField';
 4	import InputField from '../pipelines-details/multi-column-field/InputField';
 5	
 6	type PipelineRunParametersProps = {
 7	  addLabel?: string;
 8	  nameLabel: string;
 9	  nameFieldName: string;
10	  valueLabel: string;
11	  valueFieldName: string;
12	  emptyMessage: string;
13	  fieldName: string;
14	  emptyValues: { [name: string]: string };
15	  isReadOnly?: boolean;
16	  className?: string;
17	};
18	
19	const PipelineRunParameters: React.FC<PipelineRunParametersProps> = ({
20	  addLabel,
21	  nameLabel,
22	  nameFieldName,
23	  valueLabel,
24	  valueFieldName,
25	  emptyMessage,
26	  fieldName,
27	  emptyValues,
28	  isReadOnly = false,
29	  className,
30	}) => {
31	  return (
32	    <PageSection variant="light" isWidthLimited className={className}>
33	      <MultiColumnField
34	        data-test="pipeline-parameters"
35	        name={fieldName}
36	        addLabel={addLabel}
37	        headers={[
38	          {
39	            name: nameLabel,
40	            required: true,
41	          },
42	          valueLabel,
43	        ]}
44	        emptyValues={emptyValues}
45	        emptyMessage={emptyMessage}
46	        isReadOnly={isReadOnly}
47	      >
48	        <InputField
49	          data-test={nameFieldName}
50	          name={nameFieldName}
51	          type={TextInputTypes.text}
52	          placeholder={nameLabel}
53	          isDisabled={isReadOnly}
54	          aria-label={nameLabel}
55	        />
56	        <InputField
57	          data-test={valueFieldName}
58	          name={valueFieldName}
59	          type={TextInputTypes.text}
60	          placeholder={valueLabel}
61	          isDisabled={isReadOnly}
62	          aria-label={valueLabel}
63	        />
64	      </MultiColumnField>
65	    </PageSection>
66	  );
67	};
68	
69	export default PipelineRunParameters;

